import{_ as t,o as e,c as o,ag as r}from"./chunks/framework.CvgP6Fyv.js";const k=JSON.parse('{"title":"开发者文档","description":"","frontmatter":{},"headers":[{"level":1,"title":"开发者文档","slug":"开发者文档","link":"#开发者文档","children":[{"level":2,"title":"目录简介","slug":"目录简介","link":"#目录简介","children":[]},{"level":2,"title":"项目列表","slug":"项目列表","link":"#项目列表","children":[{"level":3,"title":"CAS 单点登录系统","slug":"cas-单点登录系统","link":"#cas-单点登录系统","children":[]},{"level":3,"title":"智能中间件集成验证脚手架","slug":"智能中间件集成验证脚手架","link":"#智能中间件集成验证脚手架","children":[]},{"level":3,"title":"Keycloak 扩展开发","slug":"keycloak-扩展开发","link":"#keycloak-扩展开发","children":[]}]}]}],"relativePath":"dev/index.md","filePath":"dev/index.md"}'),n={name:"dev/index.md"};function a(i,l,s,g,c,p){return e(),o("div",null,[...l[0]||(l[0]=[r('<h1 id="开发者文档" tabindex="-1">开发者文档 <a class="header-anchor" href="#开发者文档" aria-label="Permalink to &quot;开发者文档&quot;">​</a></h1><h2 id="目录简介" tabindex="-1">目录简介 <a class="header-anchor" href="#目录简介" aria-label="Permalink to &quot;目录简介&quot;">​</a></h2><p>本目录包含北京必码科技工作室提供的开发相关文档和项目，旨在帮助开发者快速上手和使用我们的技术解决方案。</p><h2 id="项目列表" tabindex="-1">项目列表 <a class="header-anchor" href="#项目列表" aria-label="Permalink to &quot;项目列表&quot;">​</a></h2><h3 id="cas-单点登录系统" tabindex="-1">CAS 单点登录系统 <a class="header-anchor" href="#cas-单点登录系统" aria-label="Permalink to &quot;CAS 单点登录系统&quot;">​</a></h3><p>CAS (Central Authentication Service) 是 Apereo 基金会维护的企业级开源单点登录系统，为企业应用提供统一的身份认证与授权机制。我们基于不同版本的 CAS Overlay 进行了定制化开发，提供了完整的开发基座、配置模板和部署方案。</p><p><strong>核心改造</strong></p><p><strong>CAS-Overlay 企业级定制开发版</strong></p><p>专为企业级身份认证场景深度二次开发，彻底重构原生 CAS 架构，开箱即用、零门槛适配企业各类账号体系，完美支撑微服务、分布式、容器化部署需求，解决原生 CAS 部署配置复杂、调试困难等核心痛点。</p><p><strong>核心二次开发功能：</strong></p><ul><li><strong>01：架构现代化升级</strong> — 摒弃传统 WAR 包架构，全面转型 SpringBoot 标准 JAR 包架构，部署流程极简优化，原生适配微服务生态与 Docker / K8s 容器化部署，兼容企业现代化运维体系。</li><li><strong>02：双源认证全覆盖 / JDBC + LDAP</strong> — 集成 MyBatis 数据库访问框架，支持 JDBC 数据库账号认证 + LDAP 目录服务双认证模式，无缝对接企业现有账号存储方案，无需改造原有账号体系，满足内网、混合架构等全场景身份校验需求。</li><li><strong>03：本地开发零障碍 / 自定义启动类</strong> — 提供专属CasWebApplication主启动类，支持本地直接 Debug 启动、断点调试，告别原生 CAS 复杂启动配置，大幅提升开发调试效率。</li><li><strong>04：灵活自定义认证逻辑</strong> — 摒弃原生固定校验规则，支持完全自定义用户名 / 密码登录校验逻辑（JDBC模式），可按需再扩展验证码、多因子校验、账号状态校验等个性化验证规则。</li><li><strong>05：双协议认证 / 任意自定义返回值</strong> — 同时支持 OAuth2.0 + OIDC 双标准认证协议，兼容各类第三方应用对接需求；支持自定义认证返回值，可灵活输出用户详情、角色权限、部门信息等任意自定义业务数据。</li><li><strong>06：分布式集群部署 / 高可用支撑</strong> — 基于 Redis 实现 Ticket 集中存储，支持多节点分布式集群部署，无状态设计保障系统高可用性、横向扩展性，满足企业高并发访问场景。</li><li><strong>07：安全加固 / 杜绝默认风险</strong> — 强制关闭 CAS 原生默认账号密码登录，全权交由自定义认证类管控，从源头消除安全漏洞，符合企业级安全管控标准。</li><li><strong>08：全量前端资源开放 / 可视化定制</strong> — 完整提取前端静态资源、页面模板，无加密、无限制，支持开发者根据企业品牌自由定制登录页、首页、错误页等前端界面。</li><li><strong>09：国际化多语言支持</strong> — 内置中文、英文等多语言配置，满足企业国际化业务、跨区域使用需求。（示例）</li><li><strong>10：容器化 / 自动化部署</strong> — 内置标准化 DockerFile 与 Jenkins 部署脚本，一键完成容器打包、自动化部署，无缝接入企业 CI / CD 持续集成流程。</li></ul><p><strong>版本选择：</strong></p><ul><li><a href="./cas-overlay/">CAS Overlay 文档</a> — 包含 7.3.x（JDK 21）、6.6.x（JDK 11）和 5.3.x（JDK 8）系列，各版本均提供 Maven 和 Gradle 两种构建方式，各版本文档包含定制化登录界面截图预览</li></ul><h3 id="智能中间件集成验证脚手架" tabindex="-1">智能中间件集成验证脚手架 <a class="header-anchor" href="#智能中间件集成验证脚手架" aria-label="Permalink to &quot;智能中间件集成验证脚手架&quot;">​</a></h3><p>智能中间件集成验证脚手架是面向开发者打造的一站式微服务项目脚手架，深度融合 AI 能力与主流中间件集成方案，支持开发者快速完成各类常用中间件服务的集成、验证与测试，大幅提升开发效率。</p><p><strong>核心功能</strong></p><p><strong>Smart-Scaffold 智能中间件集成验证脚手架</strong></p><p><strong>核心开发功能：</strong></p><p>专为企业级中间件与 AI 能力集成深度打造，一站式重构多组件验证流程，开箱即用、零代码快速验证全链路功能，完美支撑开发、测试、生产多环境部署需求，解决多中间件分散调试、AI 能力接入复杂等核心痛点。</p><ul><li><strong>01：全场景 AI 能力集成</strong> — 无缝对接 Ollama 本地大模型、OpenAI 官方 API，全面支持普通对话交互、SSE 流式实时聊天、SSE 流式文章创作、Chroma 文本向量嵌入等多元化 AI 应用场景，满足本地化与云端 AI 双重使用需求。</li><li><strong>02：全品类中间件集成验证</strong> — 一站式集成主流技术组件，原生支持 MyBatis、Elasticsearch、Kafka、MongoDB、RabbitMQ、Redis、RocketMQ、LDAP 基础操作组件，全覆盖消息队列、搜索引擎、缓存、文档库、身份协议、LDAP目录服务等中间件，快速完成接入调试、功能测试与可用性验证。</li><li><strong>03：标准化身份认证集成</strong> — 深度集成 OAuth2.0、OIDC客户端，适配统一认证中心（CAS），兼容主流企业级单点登录规范；同时内置无认证调试模式，兼顾正式环境安全授权与开发阶段快速调试。</li><li><strong>04：灵活化多数据源管理</strong> — 内置多数据源动态配置机制，可同时对接、切换、操作多个 MySQL 数据库，适配分库业务、多库并行开发等复杂数据场景。</li><li><strong>05：轻量化可视化 Web 操作界面</strong> — 基于 LayUI 搭建一体化可视化界面，零代码门槛，可视化操作即可完成各类中间件功能调试、AI 能力在线演示，大幅降低上手成本。</li><li><strong>06：全覆盖内置测试用例</strong> — 预设各类中间件、AI 模块标准化测试用例，一键执行检测，快速校验服务连通性、接口可用性与功能完整性。</li><li><strong>07：多环境无缝适配</strong> — 独立隔离开发、测试、生产多套环境配置，支持配置快速切换，完美适配本地开发、内网测试、线上部署等不同落地场景。</li><li><strong>08：容器化 / 自动化部署</strong> — 内置标准化 DockerFile 与 Jenkins 部署脚本，一键完成容器打包、自动化部署，无缝接入企业 CI / CD 持续集成流程。</li></ul><p><strong>版本选择：</strong></p><ul><li><a href="./smart-scaffold/">智能中间件集成验证脚手架文档</a> — 包含 Spring Boot 单体版、Dubbo 分布式版和 Spring Cloud 微服务版，均基于 Spring Boot 3.5.12 + Java 17，各版本文档包含系统界面截图预览</li></ul><h3 id="keycloak-扩展开发" tabindex="-1">Keycloak 扩展开发 <a class="header-anchor" href="#keycloak-扩展开发" aria-label="Permalink to &quot;Keycloak 扩展开发&quot;">​</a></h3><p>Keycloak 扩展开发是面向开发者打造的 Keycloak 扩展开发参考文档，涵盖 SPI 扩展、自定义认证流程、用户存储集成等核心功能，提供完整的开发示例和最佳实践，帮助开发者快速构建符合企业需求的 Keycloak 扩展。</p><p><strong>核心功能</strong></p><p><strong>Keycloak 扩展开发</strong></p><p><strong>核心开发功能：</strong></p><p>专为企业级 Keycloak 定制开发深度打造，一站式提供多种 SPI 扩展实现，开箱即用、零代码快速集成企业现有系统，完美支撑身份认证、事件处理、加密需求等多场景，解决 Keycloak 原生功能不足、定制复杂等核心痛点。</p><ul><li><strong>01：用户存储扩展</strong> — 支持从外部数据库读取用户信息，兼容多种数据库类型，包括 MySQL、SQL Server、Oracle、达梦、金仓、OceanBase 和 GaussDB，实现企业现有用户系统与 Keycloak 的无缝集成。</li><li><strong>02：事件监听器扩展</strong> — 将 Keycloak 的事件（如用户登录、登出、管理操作等）发送到消息队列，支持 Kafka、RabbitMQ 和 RocketMQ，便于进行审计、监控或其他业务处理。</li><li><strong>03：国密算法扩展</strong> — 集成中国国家标准密码算法（国密算法），包括 SM2、SM3 和 SM4，使 Keycloak 能够在需要使用国密算法的场景中正常工作，如政府、金融等对密码算法有特殊要求的领域。</li><li><strong>04：灵活的扩展架构</strong> — 提供可扩展的架构设计，允许开发者根据业务需求添加新的功能和支持新的服务，如添加新的数据库类型、消息队列系统或密码算法。</li><li><strong>05：完整的开发示例</strong> — 提供详细的代码实现和配置示例，帮助开发者快速理解和使用 Keycloak 扩展，减少开发和调试时间。</li><li><strong>06：标准化部署方案</strong> — 提供标准的部署方式，支持将扩展 JAR 文件放入 Keycloak 的 standalone/deployments 目录，实现快速部署和集成。</li></ul><p><strong>扩展类型：</strong></p><ul><li><a href="./keycloak-extension/">Keycloak 扩展开发文档</a> — 包含 SPI User Storage Extension、SPI Event Listener Extension 和 SPI SM Crypto Extension 三种扩展类型，详细介绍了每种扩展的实现和使用方法</li></ul>',31)])])}const h=t(n,[["render",a]]);export{k as __pageData,h as default};
